#include<bits/stdc++.h>
using namespace std;
struct COW{
	char d;
	int x,y,i;
}E_cow[51],N_cow[51];
bool N(COW a,COW b){
	return a.x<b.x;
}
bool E(COW a,COW b){
	return a.y<b.y;
}
int topN,topE;
int ans[51];
bool flag_E[51],flag_N[51];
int main()
{
	int n;
	cin>>n;
	for(int i=0;i<n;i++){
		char d;
		int x,y;
		cin>>d>>x>>y;
		if(d=='E'){
			E_cow[topE].d='E'; 
			E_cow[topE].x=x; 
			E_cow[topE].y=y;
			E_cow[topE].i=i;
			topE++; 
		}
		if(d=='N'){
			N_cow[topN].d='N'; 
			N_cow[topN].x=x; 
			N_cow[topN].y=y;
			N_cow[topN].i=i;
			topN++; 
		}
	}
	sort(&E_cow[0],&E_cow[topE],E);
	sort(&N_cow[0],&N_cow[topN],N);
	for(int i=0;i<topE;i++){
		for(int j=0;j<topN;j++){
			if(ans[N_cow[j].i])continue;
			if(N_cow[j].x>E_cow[i].x&&N_cow[j].y<E_cow[i].y){
				if(N_cow[j].x-E_cow[i].x>E_cow[i].y-N_cow[j].y){
					ans[E_cow[i].i]=N_cow[j].x-E_cow[i].x;
					break;
				}
				if(N_cow[j].x-E_cow[i].x<E_cow[i].y-N_cow[j].y){
					ans[N_cow[j].i]=E_cow[i].y-N_cow[j].y;
				}				
			}
		}
	}
	for(int i=0;i<n;i++){
		if(ans[i])
		cout<<ans[i]<<endl;
		else{
			cout<<"Infinity"<<endl;	
		}
	}
}
